fn section_1_basic_function() {
    println!("가장 단순한 함수:");
    println!();

    println!("  정의: fn(x) {{ x + 1 }}");
    println!("  호출: add_one(5)");
    println!();

    let add_one = GogsFunction::new(
        vec!["x".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            Ok(x + 1)
        }),
    );

    println!("  매개변수: {:?}", add_one.parameters);
    println!("  함수 시그니처: {}", add_one.signature());
    println!("  호출 결과: {:?}", add_one.call(&[5]));
    println!("✓ Section 1 완료: 기본 함수 정의");
}

fn section_2_multiple_parameters() {
    println!("여러 매개변수를 받는 함수:");
    println!();

    println!("  정의: fn(x, y) {{ x + y }}");
    println!("  호출: add(5, 10)");
    println!();

    let add = GogsFunction::new(
        vec!["x".to_string(), "y".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            let y = env.get("y").ok_or_else(|| "y not found".to_string())?;
            Ok(x + y)
        }),
    );

    println!("  매개변수 개수: {}", add.parameters.len());
    println!("  매개변수: {:?}", add.parameters);
    println!("  호출 결과: {:?}", add.call(&[5, 10]));
    println!();
    println!("  매개변수 검증:");
    println!("    add(5, 10, 15) → {:?}", add.call(&[5, 10, 15]));
    println!("✓ Section 2 완료: 다중 매개변수");
}

fn section_3_function_call() {
    println!("함수 호출의 흐름:");
    println!();

    println!("  1. 함수 정의");
    println!("     fn multiply(a, b) {{ a * b }}");
    println!();

    let multiply = GogsFunction::new(
        vec!["a".to_string(), "b".to_string()],
        Box::new(|env, _| {
            let a = env.get("a").ok_or_else(|| "a not found".to_string())?;
            let b = env.get("b").ok_or_else(|| "b not found".to_string())?;
            Ok(a * b)
        }),
    );

    println!("  2. 인자 준비");
    println!("     args = [3, 4]");
    println!();

    println!("  3. 함수 호출");
    println!("     multiply.call(&[3, 4])");
    println!();

    println!("  4. 환경 설정");
    println!("     Local {{ a: 3, b: 4 }}");
    println!();

    println!("  5. 계산 수행");
    println!("     a * b = 3 * 4 = 12");
    println!();

    println!("  결과: {:?}", multiply.call(&[3, 4]));
    println!("✓ Section 3 완료: 함수 호출");
}

fn section_4_function_return() {
    println!("함수 반환값:");
    println!();

    println!("  함수는 항상 값을 반환합니다");
    println!("  fn square(x) {{ x * x }}");
    println!();

    let square = GogsFunction::new(
        vec!["x".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            Ok(x * x)
        }),
    );

    for n in 1..=5 {
        let result = square.call(&[n]);
        println!("  square({}) = {:?}", n, result);
    }

    println!("✓ Section 4 완료: 함수 반환값");
}

fn section_5_closure_capture() {
    println!("클로저: 외부 변수 캡처:");
    println!();

    println!("  글로벌 환경: {{ multiplier: 10 }}");
    let mut global_env = Environment::global();
    global_env.set("multiplier".to_string(), 10);

    println!();
    println!("  정의: fn(x) {{ x * multiplier }}");
    println!();

    let scale = GogsFunction::new(
        vec!["x".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            let multiplier = env.get("multiplier").unwrap_or(1);
            Ok(x * multiplier)
        }),
    )
    .with_closure_env(global_env);

    println!("  호출: scale(5)");
    println!("  결과: {:?}", scale.call(&[5]));
    println!();
    println!("  클로저 환경:");
    scale.closure_env.dump();
    println!("✓ Section 5 완료: 클로저");
}

fn section_6_higher_order_functions() {
    println!("고차 함수: 함수를 받아서 함수를 반환:");
    println!();

    println!("  adder(n)는 '숫자 n을 더하는 함수'를 반환합니다");
    println!();

    println!("  정의: fn(x) {{ x + 5 }}");
    println!();

    let add_5 = GogsFunction::new(
        vec!["x".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            Ok(x + 5)
        }),
    );

    println!("  호출 1: add_5(10) = {:?}", add_5.call(&[10]));
    println!("  호출 2: add_5(20) = {:?}", add_5.call(&[20]));
    println!();
    println!("  이 함수는 동일한 로직을 여러 입력에 재사용합니다");
    println!("✓ Section 6 완료: 고차 함수");
}

fn section_7_function_as_argument() {
    println!("함수를 인자로 받기:");
    println!();

    println!("  apply_twice(f, x) = f(f(x))");
    println!();

    let double = GogsFunction::new(
        vec!["x".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            Ok(x * 2)
        }),
    );

    println!("  함수 f: fn(x) {{ x * 2 }}");
    println!();

    println!("  apply_twice(f, 3):");
    println!("    1. f(3) = 6");
    println!("    2. f(6) = 12");
    println!();

    let result = double.call(&[3]);
    if let Ok(val) = result {
        let result2 = double.call(&[val]);
        println!("  결과: {:?}", result2);
    }

    println!("✓ Section 7 완료: 함수를 인자로");
}

fn section_8_scope_chain() {
    println!("스코프 체인: 변수 조회 메커니즘:");
    println!();

    println!("  글로벌: {{ x: 10 }}");
    println!("    ↓");
    println!("  로컬: {{ y: 20 }}");
    println!();

    let mut global = Environment::global();
    global.set("x".to_string(), 10);

    let mut local = Environment::extend(&global);
    local.set("y".to_string(), 20);

    println!("  변수 조회:");
    println!("    x 찾기: 로컬 (없음) → 글로벌 (있음!) → 10");
    println!("    y 찾기: 로컬 (있음!) → 20");
    println!();

    let trace_x = ScopeChain::trace_lookup(&local, "x");
    println!("  x 찾기 경로:");
    for step in trace_x {
        println!("{}", step);
    }

    println!("✓ Section 8 완료: 스코프 체인");
}

fn section_9_partial_application() {
    println!("부분 적용: 일부 인자만 미리 바인딩:");
    println!();

    println!("  원래 함수: add(x, y) = x + y");
    println!("  부분 적용: add(5, _) = fn(y) {{ 5 + y }}");
    println!();

    let add = GogsFunction::new(
        vec!["x".to_string(), "y".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            let y = env.get("y").ok_or_else(|| "y not found".to_string())?;
            Ok(x + y)
        }),
    );

    println!("  add(5, 10) = {:?}", add.call(&[5, 10]));
    println!();
    println!("  부분 적용 후:");
    println!("    add_5(10) = {:?}", add.call(&[5, 10]));

    println!("✓ Section 9 완료: 부분 적용");
}

fn section_10_function_composition() {
    println!("함수 조합: f ∘ g = f(g(x)):");
    println!();

    println!("  g(x) = x * 2  (배우기)");
    println!("  f(x) = x + 1  (1 더하기)");
    println!();

    let double = |x| x * 2;
    let inc = |x| x + 1;

    println!("  g(5) = 10");
    println!("  f(g(5)) = f(10) = 11");
    println!();

    let x = 5;
    let result = inc(double(x));
    println!("  (f ∘ g)(5) = {}", result);

    println!("✓ Section 10 완료: 함수 조합");
}

fn section_11_error_handling() {
    println!("에러 처리: 매개변수 개수 불일치:");
    println!();

    let add = GogsFunction::new(
        vec!["x".to_string(), "y".to_string()],
        Box::new(|env, _| {
            let x = env.get("x").ok_or_else(|| "x not found".to_string())?;
            let y = env.get("y").ok_or_else(|| "y not found".to_string())?;
            Ok(x + y)
        }),
    );

    println!("  함수: add(x, y)");
    println!("  호출 1: add(5, 10) ← 올바름");
    println!("    결과: {:?}", add.call(&[5, 10]));
    println!();

    println!("  호출 2: add(5) ← 인자 부족");
    println!("    결과: {:?}", add.call(&[5]));
    println!();

    println!("  호출 3: add(5, 10, 15) ← 인자 초과");
    println!("    결과: {:?}", add.call(&[5, 10, 15]));

    println!("✓ Section 11 완료: 에러 처리");
}

fn section_12_designers_perspective() {
    println!();
    println!("🏆 함수의 5가지 특성:");
    println!();

    println!("특성 1: 일급 객체 (First-class Object)");
    println!("  ✓ 변수에 저장 가능");
    println!("  ✓ 함수의 인자로 전달 가능");
    println!("  ✓ 함수에서 반환 가능");
    println!();

    println!("특성 2: 클로저 (Closure)");
    println!("  ✓ 정의 시점의 환경 캡처");
    println!("  ✓ 외부 변수 접근");
    println!("  ✓ 상태 보존");
    println!();

    println!("특성 3: 렉시컬 스코프 (Lexical Scope)");
    println!("  ✓ 정의 위치에 따라 스코프 결정");
    println!("  ✓ 호출 위치와 무관");
    println!("  ✓ 스코프 체인으로 변수 조회");
    println!();

    println!("특성 4: 고차 함수 (Higher-order Function)");
    println!("  ✓ 함수를 입력으로 받음");
    println!("  ✓ 함수를 출력으로 반환");
    println!("  ✓ 함수형 프로그래밍 가능");
    println!();

    println!("특성 5: 로컬 환경 (Local Scope)");
    println!("  ✓ 함수마다 독립된 환경");
    println!("  ✓ 매개변수는 로컬에만 존재");
    println!("  ✓ 함수 종료 시 환경 소멸");
    println!();

    println!("📊 함수 호출의 라이프사이클:");
    println!();
    println!("  1. 함수 정의 → GogsFunction 생성 + 현재 환경 캡처");
    println!("  2. 함수 호출 → 인자 검증");
    println!("  3. 환경 설정 → 클로저 환경 확장");
    println!("  4. 매개변수 바인딩 → 로컬 환경에 저장");
    println!("  5. 함수 본체 실행 → 로컬 환경에서 계산");
    println!("  6. 값 반환 → 결과 값 반환");
    println!("  7. 환경 제거 → 로컬 환경 소멸");
    println!();

    println!("⚙️ 메모리 관리:");
    println!("  ✓ 클로저: 환경을 메모리에 보유");
    println!("  ✓ 로컬 변수: 함수 종료 시 정리");
    println!("  ✓ Rc를 사용한 참조 카운팅");
    println!();

    println!("🎯 프로그래밍 패턴:");
    println!("  ✓ 콜백 (Callback)");
    println!("  ✓ 데코레이터 (Decorator)");
    println!("  ✓ 팩토리 (Factory)");
    println!("  ✓ 함수형 체인 (Functional Chain)");
    println!();

    println!("✓ Section 12 완료: 설계자의 관점");
}

