fn section_8_scope_chain() {
    println!("스코프 체인: 변수 조회 메커니즘:");
    println!();

    println!("  글로벌: {{ x: 10 }}");
    println!("    ↓");
    println!("  로컬: {{ y: 20 }}");
    println!();

    let mut global = Environment::global();
    global.set("x".to_string(), 10);

    let mut local = Environment::extend(&global);
    local.set("y".to_string(), 20);

    println!("  변수 조회:");
    println!("    x 찾기: 로컬 (없음) → 글로벌 (있음!) → 10");
    println!("    y 찾기: 로컬 (있음!) → 20");
    println!();

    let trace_x = ScopeChain::trace_lookup(&local, "x");
    println!("  x 찾기 경로:");
    for step in trace_x {
        println!("{}", step);
    }

    println!("✓ Section 8 완료: 스코프 체인");
}

